     1→/**
     2→ * SlidingPuzzleGame - Canvas-based sliding tile puzzle.
     3→ * Tiles slide into the empty adjacent slot. No rotation.
     4→ * Zero dependency on gesture or input layer.
     5→ */
     6→class SlidingPuzzleGame {
     7→  /**
     8→   * @param {string} canvasId - ID of the canvas element
     9→   * @param {number} gridSize - Number of rows/columns (e.g. 3 = 3x3 = 8 tiles + 1 empty)
    10→   */
    11→  constructor(canvasId, gridSize = 3) {
    12→    this.canvas = document.getElementById(canvasId);
    13→    this.ctx = this.canvas.getContext('2d');
    14→    this.gridSize = gridSize;
    15→
    16→    // tiles[i] = original tile id at position i. -1 = empty slot
    17→    this.tiles = [];
    18→    this.emptyIndex = -1;
    19→
    20→    this.image = null;
    21→    this.imageLoaded = false;
    22→
    23→    // Board area (centered region on canvas)
    24→    this.boardArea = { x: 0, y: 0, w: 0, h: 0 };
    25→    this.tileSize = 0;
    26→
    27→    // Game state
    28→    this.moves = 0;
    29→    this.startTime = null;
    30→    this.elapsed = 0;
    31→    this.timerInterval = null;
    32→    this.won = false;
    33→
    34→    // Visual state
    35→    this.hoverIndex = -1;
    36→    this.animating = false;
    37→    this._animTile = null; // { index, fromX, fromY, toX, toY, progress }
    38→
    39→    // Callbacks
    40→    this.onStateChange = null;
    41→    this.onWin = null;
    42→
    43→    // Animation
    44→    this._animFrameId = null;
    45→    this._render = this._renderLoop.bind(this);
    46→  }
    47→
    48→  /**
    49→   * Load an image and initialize the puzzle.
    50→   * @param {string} url - Image URL or base64 data URI
    51→   * @returns {Promise<void>}
    52→   */
    53→  loadImage(url) {
    54→    return new Promise((resolve, reject) => {
    55→      const img = new Image();
    56→      img.crossOrigin = 'anonymous';
    57→      img.onload = () => {
    58→        this.image = img;
    59→        this.imageLoaded = true;
    60→        this._initPuzzle();
    61→        resolve();
    62→      };
    63→      img.onerror = () => reject(new Error('Failed to load image'));
    64→      img.src = url;
    65→    });
    66→  }
    67→
    68→  /** Calculate layout and create tiles. */
    69→  _initPuzzle() {
    70→    const cw = this.canvas.width;
    71→    const ch = this.canvas.height;
    72→
    73→    // Fit board into ~70% of the smaller dimension, centered
    74→    const maxSize = Math.min(cw * 0.7, ch * 0.85);
    75→    const imgAspect = this.image.width / this.image.height;
    76→    let boardW, boardH;
    77→
    78→    if (imgAspect > 1) {
    79→      boardW = maxSize;
    80→      boardH = maxSize / imgAspect;
    81→    } else {
    82→      boardH = maxSize;
    83→      boardW = maxSize * imgAspect;
    84→    }
    85→
    86→    // Use the smaller dimension to make square tiles
    87→    const boardSide = Math.min(boardW, boardH);
    88→    this.boardArea = {
    89→      x: (cw - boardSide) / 2,
    90→      y: (ch - boardSide) / 2,
    91→      w: boardSide,
    92→      h: boardSide,
    93→    };
    94→    this.tileSize = boardSide / this.gridSize;
    95→
    96→    this._createTiles();
    97→    this._shuffle();
    98→    this._resetState();
    99→    this._startRenderLoop();
   100→  }
   101→
   102→  /** Create solved tile array. */
   103→  _createTiles() {
   104→    const total = this.gridSize * this.gridSize;
   105→    this.tiles = [];
   106→    for (let i = 0; i < total - 1; i++) {
   107→      this.tiles.push(i);
   108→    }
   109→    this.tiles.push(-1); // empty slot is last
   110→    this.emptyIndex = total - 1;
   111→  }
   112→
   113→  /**
   114→   * Shuffle by performing random valid moves.
   115→   * This guarantees the puzzle is always solvable.
   116→   */
   117→  _shuffle() {
   118→    const n = this.gridSize;
   119→    const total = n * n;
   120→    const moveCount = total * 40; // plenty of moves for good randomization
   121→    let lastMove = -1;
   122→
   123→    for (let i = 0; i < moveCount; i++) {
   124→      const neighbors = this._getMovableNeighbors(this.emptyIndex);
   125→      // Filter out the tile we just moved (avoid undoing)
   126→      const filtered = neighbors.filter((idx) => idx !== lastMove);
   127→      const pick = filtered.length > 0 ? filtered : neighbors;
   128→      const chosen = pick[Math.floor(Math.random() * pick.length)];
   129→
   130→      lastMove = this.emptyIndex;
   131→      this.tiles[this.emptyIndex] = this.tiles[chosen];
   132→      this.tiles[chosen] = -1;
   133→      this.emptyIndex = chosen;
   134→    }
   135→  }
   136→
   137→  /** Get indices of tiles adjacent to the given position. */
   138→  _getMovableNeighbors(index) {
   139→    const n = this.gridSize;
   140→    const row = Math.floor(index / n);
   141→    const col = index % n;
   142→    const neighbors = [];
   143→
   144→    if (row > 0) neighbors.push(index - n);     // above
   145→    if (row < n - 1) neighbors.push(index + n);  // below
   146→    if (col > 0) neighbors.push(index - 1);       // left
   147→    if (col < n - 1) neighbors.push(index + 1);   // right
   148→
   149→    return neighbors;
   150→  }
   151→
   152→  /** Reset game state counters. */
   153→  _resetState() {
   154→    this.moves = 0;
   155→    this.won = false;
   156→    this.elapsed = 0;
   157→    this.startTime = null;
   158→    this.hoverIndex = -1;
   159→    this.animating = false;
   160→    this._animTile = null;
   161→    if (this.timerInterval) clearInterval(this.timerInterval);
   162→    this.timerInterval = null;
   163→    this._emitState();
   164→  }
   165→
   166→  /** Start the game timer on first interaction. */
   167→  _ensureTimerStarted() {
   168→    if (this.startTime) return;
   169→    this.startTime = Date.now();
   170→    this.timerInterval = setInterval(() => {
   171→      this.elapsed = Math.floor((Date.now() - this.startTime) / 1000);
   172→      this._emitState();
   173→    }, 500);
   174→  }
   175→
   176→  /**
   177→   * Try to slide a tile at canvas coordinates (x, y).
   178→   * Returns true if a tile was moved.
   179→   * @param {number} x - Canvas x
   180→   * @param {number} y - Canvas y
   181→   * @returns {boolean}
   182→   */
   183→  slideTileAt(x, y) {
   184→    if (this.won || this.animating) return false;
   185→
   186→    const index = this._getTileIndex(x, y);
   187→    if (index === -1) return false;
   188→
   189→    return this.slideTile(index);
   190→  }
   191→
   192→  /**
   193→   * Slide a tile by its array index.
   194→   * @param {number} index
   195→   * @returns {boolean}
   196→   */
   197→  slideTile(index) {
   198→    if (this.won || this.animating) return false;
   199→    if (this.tiles[index] === -1) return false;
   200→
   201→    // Check if adjacent to empty
   202→    const neighbors = this._getMovableNeighbors(this.emptyIndex);
   203→    if (!neighbors.includes(index)) return false;
   204→
   205→    this._ensureTimerStarted();
   206→
   207→    // Animate the slide
   208→    const n = this.gridSize;
   209→    const fromCol = index % n;
   210→    const fromRow = Math.floor(index / n);
   211→    const toCol = this.emptyIndex % n;
   212→    const toRow = Math.floor(this.emptyIndex / n);
   213→
   214→    this._animTile = {
   215→      tileId: this.tiles[index],
   216→      fromX: this.boardArea.x + fromCol * this.tileSize,
   217→      fromY: this.boardArea.y + fromRow * this.tileSize,
   218→      toX: this.boardArea.x + toCol * this.tileSize,
   219→      toY: this.boardArea.y + toRow * this.tileSize,
   220→      fromIndex: index,
   221→      toIndex: this.emptyIndex,
   222→      progress: 0,
   223→    };
   224→    this.animating = true;
   225→
   226→    return true;
   227→  }
   228→
   229→  /** Complete the animation and swap tiles. */
   230→  _completeSlide() {
   231→    if (!this._animTile) return;
   232→
   233→    const { fromIndex, toIndex } = this._animTile;
   234→    this.tiles[toIndex] = this.tiles[fromIndex];
   235→    this.tiles[fromIndex] = -1;
   236→    this.emptyIndex = fromIndex;
   237→
   238→    this.moves++;
   239→    this.animating = false;
   240→    this._animTile = null;
   241→
   242→    this._emitState();
   243→
   244→    if (this._checkWin()) {
   245→      this.won = true;
   246→      if (this.timerInterval) clearInterval(this.timerInterval);
   247→      if (this.onWin) this.onWin(this.getState());
   248→    }
   249→  }
   250→
   251→  /**
   252→   * Set hover state for the tile at canvas coordinates.
   253→   * @param {number} x
   254→   * @param {number} y
   255→   */
   256→  setHover(x, y) {
   257→    this.hoverIndex = this._getTileIndex(x, y);
   258→  }
   259→
   260→  /** Clear hover state. */
   261→  clearHover() {
   262→    this.hoverIndex = -1;
   263→  }
   264→
   265→  /**
   266→   * Get tile array index from canvas coordinates.
   267→   * Returns -1 if outside board.
   268→   */
   269→  _getTileIndex(x, y) {
   270→    const { x: bx, y: by, w: bw, h: bh } = this.boardArea;
   271→    if (x < bx || x >= bx + bw || y < by || y >= bx + bh) return -1;
   272→
   273→    const col = Math.floor((x - bx) / this.tileSize);
   274→    const row = Math.floor((y - by) / this.tileSize);
   275→    const n = this.gridSize;
   276→
   277→    if (col < 0 || col >= n || row < 0 || row >= n) return -1;
   278→    return row * n + col;
   279→  }
   280→
   281→  /** Check if all tiles are in their correct position. */
   282→  _checkWin() {
   283→    const total = this.gridSize * this.gridSize;
   284→    for (let i = 0; i < total - 1; i++) {
   285→      if (this.tiles[i] !== i) return false;
   286→    }
   287→    return this.tiles[total - 1] === -1;
   288→  }
   289→
   290→  /** Get current game state. */
   291→  getState() {
   292→    const total = this.gridSize * this.gridSize - 1;
   293→    let correct = 0;
   294→    for (let i = 0; i < total; i++) {
   295→      if (this.tiles[i] === i) correct++;
   296→    }
   297→    return {
   298→      time: this.elapsed,
   299→      moves: this.moves,
   300→      total,
   301→      correct,
   302→      completion: total > 0 ? Math.round((correct / total) * 100) : 0,
   303→      won: this.won,
   304→      gridSize: this.gridSize,
   305→    };
   306→  }
   307→
   308→  /** Emit state change to callback. */
   309→  _emitState() {
   310→    if (this.onStateChange) this.onStateChange(this.getState());
   311→  }
   312→
   313→  /** Start the render loop. */
   314→  _startRenderLoop() {
   315→    if (this._animFrameId) cancelAnimationFrame(this._animFrameId);
   316→    this._renderLoop();
   317→  }
   318→
   319→  /** Main render loop. */
   320→  _renderLoop() {
   321→    this._draw();
   322→    this._animFrameId = requestAnimationFrame(this._render);
   323→  }
   324→
   325→  /** Draw everything on the canvas. */
   326→  _draw() {
   327→    const ctx = this.ctx;
   328→    const cw = this.canvas.width;
   329→    const ch = this.canvas.height;
   330→    const n = this.gridSize;
   331→    const ts = this.tileSize;
   332→    const { x: bx, y: by } = this.boardArea;
   333→
   334→    // Clear
   335→    ctx.clearRect(0, 0, cw, ch);
   336→    ctx.fillStyle = '#09090b';
   337→    ctx.fillRect(0, 0, cw, ch);
   338→
   339→    if (!this.imageLoaded) return;
   340→
   341→    // Source tile dimensions in original image
   342→    const srcTileW = this.image.width / n;
   343→    const srcTileH = this.image.height / n;
   344→
   345→    // Advance animation
   346→    if (this.animating && this._animTile) {
   347→      this._animTile.progress += 0.15;
   348→      if (this._animTile.progress >= 1) {
   349→        this._animTile.progress = 1;
   350→        this._completeSlide();
   351→      }
   352→    }
   353→
   354→    // Draw board background
   355→    ctx.fillStyle = 'rgba(24, 24, 27, 0.8)';
   356→    ctx.fillRect(bx - 2, by - 2, this.boardArea.w + 4, this.boardArea.h + 4);
   357→    ctx.strokeStyle = 'rgba(255, 255, 255, 0.08)';
   358→    ctx.lineWidth = 2;
   359→    ctx.strokeRect(bx - 2, by - 2, this.boardArea.w + 4, this.boardArea.h + 4);
   360→
   361→    // Draw tiles
   362→    for (let i = 0; i < n * n; i++) {
   363→      const tileId = this.tiles[i];
   364→      if (tileId === -1) {
   365→        // Empty slot - draw subtle indicator
   366→        const col = i % n;
   367→        const row = Math.floor(i / n);
   368→        const dx = bx + col * ts;
   369→        const dy = by + row * ts;
   370→        ctx.fillStyle = 'rgba(204, 255, 0, 0.03)';
   371→        ctx.fillRect(dx + 1, dy + 1, ts - 2, ts - 2);
   372→        continue;
   373→      }
   374→
   375→      // Skip animating tile (drawn later on top)
   376→      if (this._animTile && this._animTile.fromIndex === i) continue;
   377→
   378→      const col = i % n;
   379→      const row = Math.floor(i / n);
   380→      const dx = bx + col * ts;
   381→      const dy = by + row * ts;
   382→
   383→      this._drawTile(ctx, tileId, dx, dy, ts, srcTileW, srcTileH, i);
   384→    }
   385→
   386→    // Draw animating tile on top
   387→    if (this.animating && this._animTile) {
   388→      const a = this._animTile;
   389→      const t = this._easeOutCubic(a.progress);
   390→      const ax = a.fromX + (a.toX - a.fromX) * t;
   391→      const ay = a.fromY + (a.toY - a.fromY) * t;
   392→
   393→      ctx.save();
   394→      ctx.shadowColor = 'rgba(204, 255, 0, 0.3)';
   395→      ctx.shadowBlur = 12;
   396→      this._drawTile(ctx, a.tileId, ax, ay, ts, srcTileW, srcTileH, -1, true);
   397→      ctx.restore();
   398→    }
   399→
   400→    // Draw grid lines
   401→    ctx.strokeStyle = 'rgba(255, 255, 255, 0.12)';
   402→    ctx.lineWidth = 1;
   403→    for (let i = 0; i <= n; i++) {
   404→      ctx.beginPath();
   405→      ctx.moveTo(bx + i * ts, by);
   406→      ctx.lineTo(bx + i * ts, by + this.boardArea.h);
   407→      ctx.stroke();
   408→
   409→      ctx.beginPath();
   410→      ctx.moveTo(bx, by + i * ts);
   411→      ctx.lineTo(bx + this.boardArea.w, by + i * ts);
   412→      ctx.stroke();
   413→    }
   414→
   415→    // Win state glow
   416→    if (this.won) {
   417→      ctx.save();
   418→      ctx.strokeStyle = 'rgba(204, 255, 0, 0.6)';
   419→      ctx.lineWidth = 4;
   420→      ctx.shadowColor = 'rgba(204, 255, 0, 0.4)';
   421→      ctx.shadowBlur = 20;
   422→      ctx.strokeRect(bx - 2, by - 2, this.boardArea.w + 4, this.boardArea.h + 4);
   423→      ctx.restore();
   424→    }
   425→  }
   426→
   427→  /** Draw a single tile. */
   428→  _drawTile(ctx, tileId, dx, dy, ts, srcTileW, srcTileH, index, isAnimating = false) {
   429→    const n = this.gridSize;
   430→    const srcCol = tileId % n;
   431→    const srcRow = Math.floor(tileId / n);
   432→
   433→    const padding = 1;
   434→
   435→    // Check if this tile is adjacent to empty and hovered
   436→    const isHovered =
   437→      !isAnimating &&
   438→      index === this.hoverIndex &&
   439→      this._getMovableNeighbors(this.emptyIndex).includes(index);
   440→
   441→    ctx.save();
   442→
   443→    // Shadow for non-animating tiles
   444→    if (!isAnimating) {
   445→      ctx.shadowColor = 'rgba(0, 0, 0, 0.3)';
   446→      ctx.shadowBlur = 4;
   447→      ctx.shadowOffsetX = 1;
   448→      ctx.shadowOffsetY = 1;
   449→    }
   450→
   451→    // Draw image slice
   452→    ctx.drawImage(
   453→      this.image,
   454→      srcCol * srcTileW,
   455→      srcRow * srcTileH,
   456→      srcTileW,
   457→      srcTileH,
   458→      dx + padding,
   459→      dy + padding,
   460→      ts - padding * 2,
   461→      ts - padding * 2
   462→    );
   463→
   464→    // Reset shadow
   465→    ctx.shadowColor = 'transparent';
   466→    ctx.shadowBlur = 0;
   467→    ctx.shadowOffsetX = 0;
   468→    ctx.shadowOffsetY = 0;
   469→
   470→    // Hover highlight
   471→    if (isHovered) {
   472→      ctx.fillStyle = 'rgba(204, 255, 0, 0.12)';
   473→      ctx.fillRect(dx + padding, dy + padding, ts - padding * 2, ts - padding * 2);
   474→      ctx.strokeStyle = 'rgba(204, 255, 0, 0.6)';
   475→      ctx.lineWidth = 2;
   476→      ctx.strokeRect(dx + padding, dy + padding, ts - padding * 2, ts - padding * 2);
   477→    }
   478→
   479→    // Tile number (small, in corner)
   480→    if (!this.won) {
   481→      ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
   482→      ctx.fillRect(dx + padding, dy + padding, 22, 18);
   483→      ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
   484→      ctx.font = '11px "JetBrains Mono", monospace';
   485→      ctx.textAlign = 'left';
   486→      ctx.textBaseline = 'top';
   487→      ctx.fillText(String(tileId + 1), dx + padding + 4, dy + padding + 3);
   488→    }
   489→
   490→    ctx.restore();
   491→  }
   492→
   493→  /** Easing function. */
   494→  _easeOutCubic(t) {
   495→    return 1 - Math.pow(1 - t, 3);
   496→  }
   497→
   498→  /** Start a new game with current settings. */
   499→  newGame() {
   500→    if (this._animFrameId) cancelAnimationFrame(this._animFrameId);
   501→    if (this.timerInterval) clearInterval(this.timerInterval);
   502→    this._initPuzzle();
   503→  }
   504→
   505→  /** Change grid size and restart. */
   506→  setGridSize(size) {
   507→    this.gridSize = size;
   508→    if (this.imageLoaded) {
   509→      this.newGame();
   510→    }
   511→  }
   512→
   513→  /** Resize the canvas and recalculate layout. */
   514→  resize(width, height) {
   515→    this.canvas.width = width;
   516→    this.canvas.height = height;
   517→    if (this.imageLoaded) {
   518→      const maxSize = Math.min(width * 0.7, height * 0.85);
   519→      const boardSide = maxSize;
   520→      this.boardArea = {
   521→        x: (width - boardSide) / 2,
   522→        y: (height - boardSide) / 2,
   523→        w: boardSide,
   524→        h: boardSide,
   525→      };
   526→      this.tileSize = boardSide / this.gridSize;
