     1→/**
     2→ * GestureController - MediaPipe HandLandmarker integration with
     3→ * ONNX-based MLP gesture classification.
     4→ *
     5→ * Gestures detected (via trained MLP model):
     6→ *   "pinch"     - Thumb tip close to index tip
     7→ *   "fist"      - All fingers curled
     8→ *   "open_hand" - All fingers extended
     9→ *   "frame"     - Two hands forming a rectangle (bypass: both hands detected)
    10→ *   "none"      - No hand or ambiguous pose
    11→ */
    12→class GestureController {
    13→  // Label order matches sklearn LabelEncoder.fit() alphabetical sorting
    14→  static GESTURE_LABELS = ['fist', 'frame', 'none', 'open_hand', 'pinch'];
    15→
    16→  /**
    17→   * @param {HTMLVideoElement} videoElement
    18→   * @param {function} onGestureChange - Called when gesture changes: (gesture, confidence, handPos)
    19→   */
    20→  constructor(videoElement, onGestureChange) {
    21→    this.video = videoElement;
    22→    this.onGestureChange = onGestureChange;
    23→
    24→    this.handLandmarker = null;
    25→    this.camera = null;
    26→    this.running = false;
    27→
    28→    // ONNX inference session
    29→    this.session = null;
    30→    this._isInferring = false;
    31→    this._lastPrediction = { gesture: 'none', confidence: 0 };
    32→
    33→    // Current state
    34→    this._gesture = 'none';
    35→    this._confidence = 0;
    36→    this._handPosition = null; // { x, y } normalized 0-1
    37→    this._landmarks = null;
    38→
    39→    // Debounce: require N consecutive frames of same gesture
    40→    this._gestureBuffer = [];
    41→    this._bufferSize = 3;
    42→
    43→    // Confidence threshold
    44→    this._confidenceThreshold = 0.7;
    45→
    46→    // Canvas for skeleton overlay
    47→    this.overlayCanvas = null;
    48→    this.overlayCtx = null;
    49→
    50→    // Animation frame
    51→    this._animFrameId = null;
    52→  }
    53→
    54→  /**
    55→   * Initialize MediaPipe, ONNX session, and start processing.
    56→   * @returns {Promise<void>}
    57→   */
    58→  async init() {
    59→    // Import MediaPipe vision module from CDN
    60→    const vision = await this._loadMediaPipe();
    61→
    62→    const { HandLandmarker, FilesetResolver } = vision;
    63→
    64→    const wasmFileset = await FilesetResolver.forVisionTasks(
    65→      'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@latest/wasm'
    66→    );
    67→
    68→    this.handLandmarker = await HandLandmarker.createFromOptions(wasmFileset, {
    69→      baseOptions: {
    70→        modelAssetPath:
    71→          'https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/latest/hand_landmarker.task',
    72→        delegate: 'GPU',
    73→      },
    74→      runningMode: 'VIDEO',
    75→      numHands: 2,
    76→      minHandDetectionConfidence: 0.5,
    77→      minHandPresenceConfidence: 0.5,
    78→      minTrackingConfidence: 0.5,
    79→    });
    80→
    81→    // Initialize ONNX inference session
    82→    await this._initONNXSession();
    83→
    84→    // Start camera
    85→    await this._startCamera();
    86→    this.running = true;
    87→    this._processLoop();
    88→  }
    89→
    90→  /** Initialize ONNX Runtime inference session. */
    91→  async _initONNXSession() {
    92→    try {
    93→      this.session = await ort.InferenceSession.create('./mlp_model.onnx', {
    94→        executionProviders: ['wasm'],
    95→      });
    96→      console.log('ONNX session initialized.');
    97→    } catch (e) {
    98→      console.warn('ONNX session failed to load, falling back to heuristic:', e);
    99→      this.session = null;
   100→    }
   101→  }
   102→
   103→  /** Dynamically import the MediaPipe vision module. */
   104→  async _loadMediaPipe() {
   105→    // Use dynamic import from CDN
   106→    const module = await import(
   107→      'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@latest'
   108→    );
   109→    return module;
   110→  }
   111→
   112→  /** Start webcam stream. */
   113→  async _startCamera() {
   114→    const stream = await navigator.mediaDevices.getUserMedia({
   115→      video: { width: 320, height: 240, facingMode: 'user' },
   116→    });
   117→    this.video.srcObject = stream;
   118→    await new Promise((resolve) => {
   119→      this.video.onloadedmetadata = () => {
   120→        this.video.play();
   121→        resolve();
   122→      };
   123→    });
   124→  }
   125→
   126→  /** Set up the skeleton overlay canvas. */
   127→  setOverlayCanvas(canvas) {
   128→    this.overlayCanvas = canvas;
   129→    this.overlayCtx = canvas.getContext('2d');
   130→  }
   131→
   132→  /** Continuous processing loop. */
   133→  _processLoop() {
   134→    if (!this.running) return;
   135→
   136→    if (this.video.readyState >= 2) {
   137→      const timestamp = performance.now();
   138→      const results = this.handLandmarker.detectForVideo(this.video, timestamp);
   139→      this._processResults(results);
   140→    }
   141→
   142→    this._animFrameId = requestAnimationFrame(() => this._processLoop());
   143→  }
   144→
   145→  /**
   146→   * Process hand detection results.
   147→   * Uses ONNX inference when available, falls back to heuristic.
   148→   * @param {object} results - MediaPipe HandLandmarker results
   149→   */
   150→  _processResults(results) {
   151→    if (!results.landmarks || results.landmarks.length === 0) {
   152→      this._updateGesture('none', 0, null);
   153→      this._landmarks = null;
   154→      this._drawOverlay(null);
   155→      return;
   156→    }
   157→
   158→    const landmarks = results.landmarks[0]; // Primary hand
   159→    this._landmarks = results.landmarks;
   160→
   161→    // Calculate hand position (palm center = landmark 9, middle finger MCP)
   162→    const palm = landmarks[9];
   163→    // Mirror x since webcam is mirrored
   164→    this._handPosition = { x: 1 - palm.x, y: palm.y };
   165→
   166→    // Two-hand bypass: frame gesture
   167→    if (results.landmarks.length >= 2) {
   168→      this._updateGesture('frame', 0.9, this._handPosition);
   169→      this._drawOverlay(results.landmarks);
   170→      return;
   171→    }
   172→
   173→    // Single hand: run ONNX inference (async, non-blocking)
   174→    if (this.session && !this._isInferring) {
   175→      this._isInferring = true;
   176→      this._runInference(landmarks).finally(() => {
   177→        this._isInferring = false;
   178→      });
   179→    } else if (!this.session) {
   180→      // Fallback to heuristic when ONNX is unavailable
   181→      const heuristic = this._classifyGesture(landmarks);
   182→      this._lastPrediction = heuristic;
   183→    }
   184→
   185→    // Use latest prediction (may be from previous frame if currently inferring)
   186→    this._updateGesture(
   187→      this._lastPrediction.gesture,
   188→      this._lastPrediction.confidence,
   189→      this._handPosition
   190→    );
   191→
   192→    // Draw skeleton overlay
   193→    this._drawOverlay(results.landmarks);
   194→  }
   195→
   196→  /**
   197→   * Run async ONNX inference on landmarks.
   198→   * @param {Array} landmarks - 21 MediaPipe hand landmarks
   199→   */
   200→  async _runInference(landmarks) {
   201→    try {
   202→      const inputData = this._preprocessLandmarks(landmarks);
   203→      if (!inputData) return;
   204→
   205→      const tensor = new ort.Tensor('float32', inputData, [1, 60]);
   206→      const results = await this.session.run({ input: tensor });
   207→      const probabilities = results.output.data;
   208→
   209→      // Find class with highest probability
   210→      let maxProb = -1;
   211→      let bestIdx = -1;
   212→      for (let i = 0; i < probabilities.length; i++) {
   213→        if (probabilities[i] > maxProb) {
   214→          maxProb = probabilities[i];
   215→          bestIdx = i;
   216→        }
   217→      }
   218→
   219→      this._lastPrediction = {
   220→        gesture: GestureController.GESTURE_LABELS[bestIdx],
   221→        confidence: maxProb,
   222→      };
   223→    } catch (error) {
   224→      console.error('Inference error:', error);
   225→    }
   226→  }
   227→
   228→  /**
   229→   * Preprocess 21 MediaPipe landmarks to match the Python training pipeline.
   230→   *
   231→   * Steps:
   232→   *   1. Translate all landmarks relative to the wrist (landmark 0).
   233→   *   2. Scale by the Euclidean distance from wrist to middle finger MCP (landmark 9).
   234→   *   3. Drop the wrist landmark (now all zeros).
   235→   *   4. Flatten to a 60-element Float32Array (20 landmarks x 3 coords).
   236→   *
   237→   * @param {Array} landmarks - Array of 21 {x, y, z} landmark objects
   238→   * @returns {Float32Array|null} - 60-dim preprocessed vector, or null if invalid
   239→   */
   240→  _preprocessLandmarks(landmarks) {
   241→    if (!landmarks || landmarks.length !== 21) return null;
   242→
   243→    const wrist = landmarks[0];
   244→    const middleMCP = landmarks[9];
   245→
   246→    // Distance from wrist to middle MCP (scaling factor)
   247→    const dx = middleMCP.x - wrist.x;
   248→    const dy = middleMCP.y - wrist.y;
   249→    const dz = middleMCP.z - wrist.z;
   250→    const scale = Math.sqrt(dx * dx + dy * dy + dz * dz) || 1.0;
   251→
   252→    const out = new Float32Array(60);
   253→    let idx = 0;
   254→
   255→    // Start from landmark 1 (drop wrist)
   256→    for (let i = 1; i < landmarks.length; i++) {
   257→      const lm = landmarks[i];
   258→      out[idx++] = (lm.x - wrist.x) / scale;
   259→      out[idx++] = (lm.y - wrist.y) / scale;
   260→      out[idx++] = (lm.z - wrist.z) / scale;
   261→    }
   262→
   263→    return out;
   264→  }
   265→
   266→  /**
   267→   * Heuristic gesture classifier (fallback when ONNX is unavailable).
   268→   * Uses distances between finger tips and palm base.
   269→   *
   270→   * Landmark indices (per hand):
   271→   *   0: wrist
   272→   *   1-4: thumb (CMC, MCP, IP, TIP)
   273→   *   5-8: index (MCP, PIP, DIP, TIP)
   274→   *   9-12: middle (MCP, PIP, DIP, TIP)
   275→   *   13-16: ring (MCP, PIP, DIP, TIP)
   276→   *   17-20: pinky (MCP, PIP, DIP, TIP)
   277→   */
   278→  _classifyGesture(lm) {
   279→    const thumbTip = lm[4];
   280→    const indexTip = lm[8];
   281→    const middleTip = lm[12];
   282→    const ringTip = lm[16];
   283→    const pinkyTip = lm[20];
   284→
   285→    const indexMCP = lm[5];
   286→    const middleMCP = lm[9];
   287→    const ringMCP = lm[13];
   288→    const pinkyMCP = lm[17];
   289→
   290→    const wrist = lm[0];
   291→
   292→    // Finger extension: tip is farther from wrist than MCP
   293→    const fingerExtended = (tip, mcp) => {
   294→      const tipDist = this._dist3D(tip, wrist);
   295→      const mcpDist = this._dist3D(mcp, wrist);
   296→      return tipDist > mcpDist * 1.1;
   297→    };
   298→
   299→    const indexExt = fingerExtended(indexTip, indexMCP);
   300→    const middleExt = fingerExtended(middleTip, middleMCP);
   301→    const ringExt = fingerExtended(ringTip, ringMCP);
   302→    const pinkyExt = fingerExtended(pinkyTip, pinkyMCP);
   303→
   304→    // Thumb extension (compare to index MCP)
   305→    const thumbExt = this._dist3D(thumbTip, wrist) > this._dist3D(lm[2], wrist) * 1.1;
   306→
   307→    // Pinch: thumb tip close to index tip
   308→    const pinchDist = this._dist3D(thumbTip, indexTip);
   309→    if (pinchDist < 0.06) {
   310→      return { gesture: 'pinch', confidence: Math.min(1, 1 - pinchDist / 0.06) };
   311→    }
   312→
   313→    // Count extended fingers
   314→    const extCount = [indexExt, middleExt, ringExt, pinkyExt].filter(Boolean).length;
   315→
   316→    // Fist: no fingers extended (and thumb not extended)
   317→    if (extCount === 0 && !thumbExt) {
   318→      return { gesture: 'fist', confidence: 0.85 };
   319→    }
   320→
   321→    // Open hand: all fingers extended
   322→    if (extCount >= 3 && thumbExt) {
   323→      return { gesture: 'open_hand', confidence: 0.8 + extCount * 0.04 };
   324→    }
   325→
   326→    // Default: none with low confidence
   327→    return { gesture: 'none', confidence: 0.3 };
   328→  }
   329→
   330→  /** 3D Euclidean distance between two landmarks. */
   331→  _dist3D(a, b) {
   332→    return Math.sqrt((a.x - b.x) ** 2 + (a.y - b.y) ** 2 + (a.z - b.z) ** 2);
   333→  }
   334→
   335→  /**
   336→   * Update gesture with debounce buffer.
   337→   * Only fires callback when gesture is stable for N frames.
   338→   */
   339→  _updateGesture(gesture, confidence, handPos) {
   340→    // Apply confidence threshold
   341→    const effectiveGesture =
   342→      confidence >= this._confidenceThreshold ? gesture : 'none';
   343→
   344→    this._gestureBuffer.push(effectiveGesture);
   345→    if (this._gestureBuffer.length > this._bufferSize) {
   346→      this._gestureBuffer.shift();
   347→    }
   348→
   349→    // Check if all buffer entries match
   350→    const stable = this._gestureBuffer.every(
   351→      (g) => g === this._gestureBuffer[0]
   352→    );
   353→    const stableGesture = stable ? this._gestureBuffer[0] : this._gesture;
   354→
   355→    if (stableGesture !== this._gesture) {
   356→      this._gesture = stableGesture;
   357→      this._confidence = confidence;
   358→      if (this.onGestureChange) {
   359→        this.onGestureChange(this._gesture, this._confidence, handPos);
   360→      }
   361→    } else {
   362→      this._confidence = confidence;
   363→    }
   364→
   365→    // Always update hand position callback for smooth tracking
   366→    if (handPos && this.onGestureChange && this._gesture !== 'none') {
   367→      this.onGestureChange(this._gesture, this._confidence, handPos);
   368→    }
   369→  }
   370→
   371→  /** Draw hand skeleton on overlay canvas. */
   372→  _drawOverlay(allLandmarks) {
   373→    if (!this.overlayCanvas || !this.overlayCtx) return;
   374→    const ctx = this.overlayCtx;
   375→    const w = this.overlayCanvas.width;
   376→    const h = this.overlayCanvas.height;
   377→
   378→    ctx.clearRect(0, 0, w, h);
   379→
   380→    if (!allLandmarks) return;
   381→
   382→    // Connection pairs for hand skeleton
   383→    const connections = [
   384→      [0, 1], [1, 2], [2, 3], [3, 4],       // thumb
   385→      [0, 5], [5, 6], [6, 7], [7, 8],       // index
   386→      [0, 9], [9, 10], [10, 11], [11, 12],  // middle
   387→      [0, 13], [13, 14], [14, 15], [15, 16],// ring
   388→      [0, 17], [17, 18], [18, 19], [19, 20],// pinky
   389→      [5, 9], [9, 13], [13, 17],            // palm
   390→    ];
   391→
   392→    for (const landmarks of allLandmarks) {
   393→      // Draw connections
   394→      ctx.strokeStyle = 'rgba(100, 180, 255, 0.7)';
   395→      ctx.lineWidth = 2;
   396→      for (const [a, b] of connections) {
   397→        ctx.beginPath();
   398→        // Mirror x for display
   399→        ctx.moveTo((1 - landmarks[a].x) * w, landmarks[a].y * h);
   400→        ctx.lineTo((1 - landmarks[b].x) * w, landmarks[b].y * h);
   401→        ctx.stroke();
   402→      }
   403→
   404→      // Draw landmarks
   405→      for (let i = 0; i < landmarks.length; i++) {
   406→        const lm = landmarks[i];
   407→        ctx.beginPath();
   408→        ctx.arc((1 - lm.x) * w, lm.y * h, 3, 0, Math.PI * 2);
   409→        ctx.fillStyle =
   410→          i === 4 || i === 8 ? 'rgba(255, 100, 100, 0.9)' : 'rgba(255, 255, 255, 0.8)';
   411→        ctx.fill();
   412→      }
   413→    }
   414→  }
   415→
   416→  /** Get current hand position (normalized 0-1, mirrored). */
   417→  getHandPosition() {
   418→    return this._handPosition;
   419→  }
   420→
   421→  /** Get current gesture name. */
   422→  getCurrentGesture() {
   423→    return this._gesture;
   424→  }
   425→
   426→  /** Get current confidence. */
   427→  getConfidence() {
   428→    return this._confidence;
   429→  }
   430→
   431→  /** Stop processing and release resources. */
   432→  destroy() {
   433→    this.running = false;
   434→    if (this._animFrameId) cancelAnimationFrame(this._animFrameId);
   435→    if (this.video.srcObject) {
   436→      this.video.srcObject.getTracks().forEach((t) => t.stop());
   437→      this.video.srcObject = null;
   438→    }
   439→    if (this.handLandmarker) {
   440→      this.handLandmarker.close();
   441→      this.handLandmarker = null;
   442→    }
   443→  }
   444→}
