     7→
     8→  // ---------------------------------------------------------------
     9→  // Leaderboard (localStorage)
    10→  // ---------------------------------------------------------------
    11→  const LEADERBOARD_KEY = 'sliding-puzzle-leaderboard';
    12→  const MAX_ENTRIES = 20;
    13→
    14→  function loadLeaderboard() {
    15→    try {
    16→      const data = localStorage.getItem(LEADERBOARD_KEY);
    17→      return data ? JSON.parse(data) : [];
    18→    } catch {
    19→      return [];
    20→    }
    21→  }
    22→
    23→  function saveLeaderboard(entries) {
    24→    localStorage.setItem(LEADERBOARD_KEY, JSON.stringify(entries));
    25→  }
    26→
    27→  function addLeaderboardEntry(name, time, moves, gridSize) {
    28→    const entries = loadLeaderboard();
    29→    entries.push({ name, time, moves, gridSize, date: Date.now() });
    30→    entries.sort((a, b) => a.time - b.time || a.moves - b.moves);
    31→    const trimmed = entries.slice(0, MAX_ENTRIES);
    32→    saveLeaderboard(trimmed);
    33→    return trimmed;
    34→  }
    35→
    36→  function formatTime(seconds) {
    37→    const m = Math.floor(seconds / 60).toString().padStart(2, '0');
    38→    const s = (seconds % 60).toString().padStart(2, '0');
    39→    return m + ':' + s;
    40→  }
    41→
    42→  // ---------------------------------------------------------------
    43→  // Sample image generator
    44→  // ---------------------------------------------------------------
    45→  function generateSampleImage() {
    46→    const c = document.createElement('canvas');
    47→    c.width = 400;
    48→    c.height = 400;
    49→    const ctx = c.getContext('2d');
    50→
    51→    const g1 = ctx.createLinearGradient(0, 0, 400, 400);
    52→    g1.addColorStop(0, '#ff6b6b');
    53→    g1.addColorStop(0.25, '#feca57');
    54→    g1.addColorStop(0.5, '#48dbfb');
    55→    g1.addColorStop(0.75, '#ff9ff3');
    56→    g1.addColorStop(1, '#54a0ff');
    57→    ctx.fillStyle = g1;
    58→    ctx.fillRect(0, 0, 400, 400);
    59→
    60→    ctx.globalAlpha = 0.3;
    61→    const colors = ['#fff', '#2d3436', '#6c5ce7', '#00b894', '#fdcb6e'];
    62→    for (let i = 0; i < 12; i++) {
    63→      ctx.beginPath();
    64→      ctx.arc(
    65→        50 + Math.random() * 300,
    66→        50 + Math.random() * 300,
    67→        15 + Math.random() * 40,
    68→        0,
    69→        Math.PI * 2
    70→      );
    71→      ctx.fillStyle = colors[i % colors.length];
    72→      ctx.fill();
    73→    }
    74→
    75→    ctx.globalAlpha = 0.15;
    76→    ctx.fillStyle = '#fff';
    77→    ctx.font = 'bold 50px sans-serif';
    78→    ctx.textAlign = 'center';
    79→    ctx.textBaseline = 'middle';
    80→    ctx.fillText('SLIDE', 200, 170);
    81→    ctx.font = 'bold 36px sans-serif';
    82→    ctx.fillText('PUZZLE', 200, 230);
    83→    ctx.globalAlpha = 1;
    84→
    85→    return c.toDataURL('image/png');
    86→  }
