/**
 * SlidingPuzzleGame - Canvas-based sliding tile puzzle.
 * Tiles slide into the empty adjacent slot. No rotation.
 * Zero dependency on gesture or input layer.
 */
class SlidingPuzzleGame {
  /**
   * @param {string} canvasId - ID of the canvas element
   * @param {number} gridSize - Number of rows/columns (e.g. 3 = 3x3 = 8 tiles + 1 empty)
   */
  constructor(canvasId, gridSize = 3) {
    this.canvas = document.getElementById(canvasId);
    this.ctx = this.canvas.getContext('2d');
    this.gridSize = gridSize;

    // tiles[i] = original tile id at position i. -1 = empty slot
    this.tiles = [];
    this.emptyIndex = -1;

    this.image = null;
    this.imageLoaded = false;

    // Board area (centered region on canvas)
    this.boardArea = { x: 0, y: 0, w: 0, h: 0 };
    this.tileSize = 0;

    // Game state
    this.moves = 0;
    this.startTime = null;
    this.elapsed = 0;
    this.timerInterval = null;
    this.won = false;

    // Visual state
    this.hoverIndex = -1;
    this.animating = false;
    this._animTile = null; // { index, fromX, fromY, toX, toY, progress }

    // Callbacks
    this.onStateChange = null;
    this.onWin = null;

    // Animation
    this._animFrameId = null;
    this._render = this._renderLoop.bind(this);
  }

  /**
   * Load an image and initialize the puzzle.
   * @param {string} url - Image URL or base64 data URI
   * @returns {Promise<void>}
   */
  loadImage(url) {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = 'anonymous';
      img.onload = () => {
        this.image = img;
        this.imageLoaded = true;
        this._initPuzzle();
        resolve();
      };
      img.onerror = () => reject(new Error('Failed to load image'));
      img.src = url;
    });
  }

  /** Calculate layout and create tiles. */
  _initPuzzle() {
    const cw = this.canvas.width;
    const ch = this.canvas.height;

    // Fit board into ~70% of the smaller dimension, centered
    const maxSize = Math.min(cw * 0.7, ch * 0.85);
    const imgAspect = this.image.width / this.image.height;
    let boardW, boardH;

    if (imgAspect > 1) {
      boardW = maxSize;
      boardH = maxSize / imgAspect;
    } else {
      boardH = maxSize;
      boardW = maxSize * imgAspect;
    }

    // Use the smaller dimension to make square tiles
    const boardSide = Math.min(boardW, boardH);
    this.boardArea = {
      x: (cw - boardSide) / 2,
      y: (ch - boardSide) / 2,
      w: boardSide,
      h: boardSide,
    };
    this.tileSize = boardSide / this.gridSize;

    this._createTiles();
    this._shuffle();
    this._resetState();
    this._startRenderLoop();
  }

  /** Create solved tile array. */
  _createTiles() {
    const total = this.gridSize * this.gridSize;
    this.tiles = [];
    for (let i = 0; i < total - 1; i++) {
      this.tiles.push(i);
    }
    this.tiles.push(-1); // empty slot is last
    this.emptyIndex = total - 1;
  }

  /**
   * Shuffle by performing random valid moves.
   * This guarantees the puzzle is always solvable.
   */
  _shuffle() {
    const n = this.gridSize;
    const total = n * n;
    const moveCount = total * 40; // plenty of moves for good randomization
    let lastMove = -1;

    for (let i = 0; i < moveCount; i++) {
      const neighbors = this._getMovableNeighbors(this.emptyIndex);
      // Filter out the tile we just moved (avoid undoing)
      const filtered = neighbors.filter((idx) => idx !== lastMove);
      const pick = filtered.length > 0 ? filtered : neighbors;
      const chosen = pick[Math.floor(Math.random() * pick.length)];

      lastMove = this.emptyIndex;
      this.tiles[this.emptyIndex] = this.tiles[chosen];
      this.tiles[chosen] = -1;
      this.emptyIndex = chosen;
    }
  }

  /** Get indices of tiles adjacent to the given position. */
  _getMovableNeighbors(index) {
    const n = this.gridSize;
    const row = Math.floor(index / n);
    const col = index % n;
    const neighbors = [];

    if (row > 0) neighbors.push(index - n);     // above
    if (row < n - 1) neighbors.push(index + n);  // below
    if (col > 0) neighbors.push(index - 1);       // left
    if (col < n - 1) neighbors.push(index + 1);   // right

    return neighbors;
  }

  /** Reset game state counters. */
  _resetState() {
    this.moves = 0;
    this.won = false;
    this.elapsed = 0;
    this.startTime = null;
    this.hoverIndex = -1;
    this.animating = false;
    this._animTile = null;
    if (this.timerInterval) clearInterval(this.timerInterval);
    this.timerInterval = null;
    this._emitState();
  }

  /** Start the game timer on first interaction. */
  _ensureTimerStarted() {
    if (this.startTime) return;
    this.startTime = Date.now();
    this.timerInterval = setInterval(() => {
      this.elapsed = Math.floor((Date.now() - this.startTime) / 1000);
      this._emitState();
    }, 500);
  }

  /**
   * Try to slide a tile at canvas coordinates (x, y).
   * Returns true if a tile was moved.
   * @param {number} x - Canvas x
   * @param {number} y - Canvas y
   * @returns {boolean}
   */
  slideTileAt(x, y) {
    if (this.won || this.animating) return false;

    const index = this._getTileIndex(x, y);
    if (index === -1) return false;

    return this.slideTile(index);
  }

  /**
   * Slide a tile by its array index.
   * @param {number} index
   * @returns {boolean}
   */
  slideTile(index) {
    if (this.won || this.animating) return false;
    if (this.tiles[index] === -1) return false;

    // Check if adjacent to empty
    const neighbors = this._getMovableNeighbors(this.emptyIndex);
    if (!neighbors.includes(index)) return false;

    this._ensureTimerStarted();

    // Animate the slide
    const n = this.gridSize;
    const fromCol = index % n;
    const fromRow = Math.floor(index / n);
    const toCol = this.emptyIndex % n;
    const toRow = Math.floor(this.emptyIndex / n);

    this._animTile = {
      tileId: this.tiles[index],
      fromX: this.boardArea.x + fromCol * this.tileSize,
      fromY: this.boardArea.y + fromRow * this.tileSize,
      toX: this.boardArea.x + toCol * this.tileSize,
      toY: this.boardArea.y + toRow * this.tileSize,
      fromIndex: index,
      toIndex: this.emptyIndex,
      progress: 0,
    };
    this.animating = true;

    return true;
  }

  /** Complete the animation and swap tiles. */
  _completeSlide() {
    if (!this._animTile) return;

    const { fromIndex, toIndex } = this._animTile;
    this.tiles[toIndex] = this.tiles[fromIndex];
    this.tiles[fromIndex] = -1;
    this.emptyIndex = fromIndex;

    this.moves++;
    this.animating = false;
    this._animTile = null;

    this._emitState();

    if (this._checkWin()) {
      this.won = true;
      if (this.timerInterval) clearInterval(this.timerInterval);
      if (this.onWin) this.onWin(this.getState());
    }
  }

  /**
   * Set hover state for the tile at canvas coordinates.
   * @param {number} x
   * @param {number} y
   */
  setHover(x, y) {
    this.hoverIndex = this._getTileIndex(x, y);
  }

  /** Clear hover state. */
  clearHover() {
    this.hoverIndex = -1;
  }

  /**
   * Get tile array index from canvas coordinates.
   * Returns -1 if outside board.
   */
  _getTileIndex(x, y) {
    const { x: bx, y: by, w: bw, h: bh } = this.boardArea;
    if (x < bx || x >= bx + bw || y < by || y >= bx + bh) return -1;

    const col = Math.floor((x - bx) / this.tileSize);
    const row = Math.floor((y - by) / this.tileSize);
    const n = this.gridSize;

    if (col < 0 || col >= n || row < 0 || row >= n) return -1;
    return row * n + col;
  }

  /** Check if all tiles are in their correct position. */
  _checkWin() {
    const total = this.gridSize * this.gridSize;
    for (let i = 0; i < total - 1; i++) {
      if (this.tiles[i] !== i) return false;
    }
    return this.tiles[total - 1] === -1;
  }

  /** Get current game state. */
  getState() {
    const total = this.gridSize * this.gridSize - 1;
    let correct = 0;
    for (let i = 0; i < total; i++) {
      if (this.tiles[i] === i) correct++;
    }
    return {
      time: this.elapsed,
      moves: this.moves,
      total,
      correct,
      completion: total > 0 ? Math.round((correct / total) * 100) : 0,
      won: this.won,
      gridSize: this.gridSize,
    };
  }

  /** Emit state change to callback. */
  _emitState() {
    if (this.onStateChange) this.onStateChange(this.getState());
  }

  /** Start the render loop. */
  _startRenderLoop() {
    if (this._animFrameId) cancelAnimationFrame(this._animFrameId);
    this._renderLoop();
  }

  /** Main render loop. */
  _renderLoop() {
    this._draw();
    this._animFrameId = requestAnimationFrame(this._render);
  }

  /** Draw everything on the canvas. */
  _draw() {
    const ctx = this.ctx;
    const cw = this.canvas.width;
    const ch = this.canvas.height;
    const n = this.gridSize;
    const ts = this.tileSize;
    const { x: bx, y: by } = this.boardArea;

    // Clear
    ctx.clearRect(0, 0, cw, ch);
    ctx.fillStyle = '#09090b';
    ctx.fillRect(0, 0, cw, ch);

    if (!this.imageLoaded) return;

    // Source tile dimensions in original image
    const srcTileW = this.image.width / n;
    const srcTileH = this.image.height / n;

    // Advance animation
    if (this.animating && this._animTile) {
      this._animTile.progress += 0.15;
      if (this._animTile.progress >= 1) {
        this._animTile.progress = 1;
        this._completeSlide();
      }
    }

    // Draw board background
    ctx.fillStyle = 'rgba(24, 24, 27, 0.8)';
    ctx.fillRect(bx - 2, by - 2, this.boardArea.w + 4, this.boardArea.h + 4);
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.08)';
    ctx.lineWidth = 2;
    ctx.strokeRect(bx - 2, by - 2, this.boardArea.w + 4, this.boardArea.h + 4);

    // Draw tiles
    for (let i = 0; i < n * n; i++) {
      const tileId = this.tiles[i];
      if (tileId === -1) {
        // Empty slot - draw subtle indicator
        const col = i % n;
        const row = Math.floor(i / n);
        const dx = bx + col * ts;
        const dy = by + row * ts;
        ctx.fillStyle = 'rgba(204, 255, 0, 0.03)';
        ctx.fillRect(dx + 1, dy + 1, ts - 2, ts - 2);
        continue;
      }

      // Skip animating tile (drawn later on top)
      if (this._animTile && this._animTile.fromIndex === i) continue;

      const col = i % n;
      const row = Math.floor(i / n);
      const dx = bx + col * ts;
      const dy = by + row * ts;

      this._drawTile(ctx, tileId, dx, dy, ts, srcTileW, srcTileH, i);
    }

    // Draw animating tile on top
    if (this.animating && this._animTile) {
      const a = this._animTile;
      const t = this._easeOutCubic(a.progress);
      const ax = a.fromX + (a.toX - a.fromX) * t;
      const ay = a.fromY + (a.toY - a.fromY) * t;

      ctx.save();
      ctx.shadowColor = 'rgba(204, 255, 0, 0.3)';
      ctx.shadowBlur = 12;
      this._drawTile(ctx, a.tileId, ax, ay, ts, srcTileW, srcTileH, -1, true);
      ctx.restore();
    }

    // Draw grid lines
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.12)';
    ctx.lineWidth = 1;
    for (let i = 0; i <= n; i++) {
      ctx.beginPath();
      ctx.moveTo(bx + i * ts, by);
      ctx.lineTo(bx + i * ts, by + this.boardArea.h);
      ctx.stroke();

      ctx.beginPath();
      ctx.moveTo(bx, by + i * ts);
      ctx.lineTo(bx + this.boardArea.w, by + i * ts);
      ctx.stroke();
    }

    // Win state glow
    if (this.won) {
      ctx.save();
      ctx.strokeStyle = 'rgba(204, 255, 0, 0.6)';
      ctx.lineWidth = 4;
      ctx.shadowColor = 'rgba(204, 255, 0, 0.4)';
      ctx.shadowBlur = 20;
      ctx.strokeRect(bx - 2, by - 2, this.boardArea.w + 4, this.boardArea.h + 4);
      ctx.restore();
    }
  }

  /** Draw a single tile. */
  _drawTile(ctx, tileId, dx, dy, ts, srcTileW, srcTileH, index, isAnimating = false) {
    const n = this.gridSize;
    const srcCol = tileId % n;
    const srcRow = Math.floor(tileId / n);

    const padding = 1;

    // Check if this tile is adjacent to empty and hovered
    const isHovered =
      !isAnimating &&
      index === this.hoverIndex &&
      this._getMovableNeighbors(this.emptyIndex).includes(index);

    ctx.save();

    // Shadow for non-animating tiles
    if (!isAnimating) {
      ctx.shadowColor = 'rgba(0, 0, 0, 0.3)';
      ctx.shadowBlur = 4;
      ctx.shadowOffsetX = 1;
      ctx.shadowOffsetY = 1;
    }

    // Draw image slice
    ctx.drawImage(
      this.image,
      srcCol * srcTileW,
      srcRow * srcTileH,
      srcTileW,
      srcTileH,
      dx + padding,
      dy + padding,
      ts - padding * 2,
      ts - padding * 2
    );

    // Reset shadow
    ctx.shadowColor = 'transparent';
    ctx.shadowBlur = 0;
    ctx.shadowOffsetX = 0;
    ctx.shadowOffsetY = 0;

    // Hover highlight
    if (isHovered) {
      ctx.fillStyle = 'rgba(204, 255, 0, 0.12)';
      ctx.fillRect(dx + padding, dy + padding, ts - padding * 2, ts - padding * 2);
      ctx.strokeStyle = 'rgba(204, 255, 0, 0.6)';
      ctx.lineWidth = 2;
      ctx.strokeRect(dx + padding, dy + padding, ts - padding * 2, ts - padding * 2);
    }

    // Tile number (small, in corner)
    if (!this.won) {
      ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
      ctx.fillRect(dx + padding, dy + padding, 22, 18);
      ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
      ctx.font = '11px "JetBrains Mono", monospace';
      ctx.textAlign = 'left';
      ctx.textBaseline = 'top';
      ctx.fillText(String(tileId + 1), dx + padding + 4, dy + padding + 3);
    }

    ctx.restore();
  }

  /** Easing function. */
  _easeOutCubic(t) {
    return 1 - Math.pow(1 - t, 3);
  }

  /** Start a new game with current settings. */
  newGame() {
    if (this._animFrameId) cancelAnimationFrame(this._animFrameId);
    if (this.timerInterval) clearInterval(this.timerInterval);
    this._initPuzzle();
  }

  /** Change grid size and restart. */
  setGridSize(size) {
    this.gridSize = size;
    if (this.imageLoaded) {
      this.newGame();
    }
  }

  /** Resize the canvas and recalculate layout. */
  resize(width, height) {
    this.canvas.width = width;
    this.canvas.height = height;
    if (this.imageLoaded) {
      const maxSize = Math.min(width * 0.7, height * 0.85);
      const boardSide = maxSize;
      this.boardArea = {
        x: (width - boardSide) / 2,
        y: (height - boardSide) / 2,
        w: boardSide,
        h: boardSide,
      };
      this.tileSize = boardSide / this.gridSize;
    }
  }

  /** Clean up resources. */
  destroy() {
    if (this._animFrameId) cancelAnimationFrame(this._animFrameId);
    if (this.timerInterval) clearInterval(this.timerInterval);
  }
}

