}

/* --- App container --- */
.app {
  position: relative;
  width: 100vw;
  height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}

/* --- Title bar --- */
.title-bar {
  position: absolute;
  top: 16px;
  left: 0;
  right: 0;
  text-align: center;
  z-index: 10;
  pointer-events: none;
}

.title {
  font-size: 24px;
  font-weight: 700;
  letter-spacing: 4px;
  color: var(--accent);
  text-transform: uppercase;
  text-shadow: 0 2px 10px rgba(204, 255, 0, 0.3);
}

.subtitle {
  font-size: 12px;
  color: var(--text-muted);
  margin-top: 4px;
}

/* --- Canvas --- */
#game-canvas {
  display: block;
  width: 95vw;
  height: 85vh;
  background: var(--bg-surface);
  border-radius: var(--radius-lg);
  border: 1px solid rgba(255, 255, 255, 0.05);
  box-shadow: 0 24px 64px rgba(0, 0, 0, 0.5);
  object-fit: cover;
}

/* --- Hidden video --- */
#webcam {
  display: none;
}

/* --- File input --- */
.file-input-hidden {
  display: none;
}

/* ============================================================
   Floating HUD Elements
   ============================================================ */

/* Timer (top-center) */
.hud-timer {
  position: absolute;
  top: 72px;
  left: 50%;
  transform: translateX(-50%);
  z-index: 20;
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 20px;
  background: var(--bg-glass);
  backdrop-filter: blur(var(--blur));
  -webkit-backdrop-filter: blur(var(--blur));
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.4);
  animation: slideDown 0.5s ease;
}

.timer-icon {
  color: var(--accent);
  font-size: 14px;
}

.timer-value {
  font-size: 18px;
  font-weight: 700;
  font-variant-numeric: tabular-nums;
  letter-spacing: 2px;
}

/* Leaderboard button (top-left) */
