     1→/**
     2→ * SwapPuzzle - Canvas-based tile swap puzzle.
     3→ * Tiles are shuffled via Fisher-Yates and swapped by drag-and-drop.
     4→ * No dependency on input layer.
     5→ */
     6→const SwapPuzzle = {
     7→  /**
     8→   * Generate shuffled puzzle tiles.
     9→   * @param {number} cols
    10→   * @param {number} rows
    11→   * @returns {Array} Array of tile objects { id, origX, origY }
    12→   */
    13→  generate(cols, rows) {
    14→    const tiles = [];
    15→    for (let y = 0; y < rows; y++) {
    16→      for (let x = 0; x < cols; x++) {
    17→        tiles.push({ id: y * cols + x, origX: x, origY: y });
    18→      }
    19→    }
    20→    // Fisher-Yates shuffle
    21→    for (let i = tiles.length - 1; i > 0; i--) {
    22→      const j = Math.floor(Math.random() * (i + 1));
    23→      [tiles[i], tiles[j]] = [tiles[j], tiles[i]];
    24→    }
    25→    return tiles;
    26→  },
    27→
    28→  /**
    29→   * Check if puzzle is solved (every tile at its original index).
    30→   * @param {Array} tiles
    31→   * @returns {boolean}
    32→   */
    33→  isSolved(tiles) {
    34→    return tiles.every((tile, index) => tile.id === index);
    35→  },
    36→
    37→  /**
    38→   * Render the puzzle board.
    39→   * @param {CanvasRenderingContext2D} ctx
    40→   * @param {HTMLCanvasElement} image - Source image canvas
    41→   * @param {Array} tiles - Current tile arrangement
    42→   * @param {number} cols
    43→   * @param {number} rows
    44→   * @param {number} width - Board pixel width
    45→   * @param {number} height - Board pixel height
    46→   * @param {object|null} drag - { index, x, y } where x,y are relative to board
    47→   * @param {number|null} hoverIdx - Tile index under cursor
    48→   */
    49→  render(ctx, image, tiles, cols, rows, width, height, drag, hoverIdx) {
    50→    const tileW = width / cols;
    51→    const tileH = height / rows;
    52→    const srcTileW = image.width / cols;
    53→    const srcTileH = image.height / rows;
    54→
    55→    // Background
    56→    ctx.fillStyle = '#111';
    57→    ctx.fillRect(0, 0, width, height);
    58→
    59→    // Draw grid tiles
    60→    tiles.forEach((tile, i) => {
    61→      const dx = (i % cols) * tileW;
    62→      const dy = Math.floor(i / cols) * tileH;
    63→      const sx = tile.origX * srcTileW;
    64→      const sy = tile.origY * srcTileH;
    65→
    66→      if (drag && drag.index === i) {
    67→        // Empty slot where dragged tile was
    68→        ctx.fillStyle = '#222';
    69→        ctx.fillRect(dx, dy, tileW, tileH);
    70→        ctx.strokeStyle = '#333';
    71→        ctx.strokeRect(dx, dy, tileW, tileH);
    72→      } else if (drag && hoverIdx === i) {
    73→        // Potential swap target - dimmed with green tint
    74→        ctx.save();
    75→        ctx.globalAlpha = 0.5;
    76→        ctx.drawImage(image, sx, sy, srcTileW, srcTileH, dx, dy, tileW, tileH);
    77→        ctx.fillStyle = 'rgba(204, 255, 0, 0.2)';
    78→        ctx.fillRect(dx, dy, tileW, tileH);
    79→        ctx.strokeStyle = '#ccff00';
    80→        ctx.lineWidth = 2;
    81→        ctx.strokeRect(dx, dy, tileW, tileH);
    82→        ctx.restore();
    83→      } else {
    84→        // Normal tile
    85→        ctx.drawImage(image, sx, sy, srcTileW, srcTileH, dx, dy, tileW, tileH);
    86→        ctx.strokeStyle = '#ffffff';
    87→        ctx.lineWidth = 1;
    88→        ctx.strokeRect(dx, dy, tileW, tileH);
    89→      }
    90→    });
    91→
    92→    // Draw dragged tile on top (slightly larger, with shadow)
    93→    if (drag) {
    94→      const tile = tiles[drag.index];
    95→      const sx = tile.origX * srcTileW;
    96→      const sy = tile.origY * srcTileH;
    97→      const dragW = tileW * 1.1;
    98→      const dragH = tileH * 1.1;
    99→      const ddx = drag.x - dragW / 2;
   100→      const ddy = drag.y - dragH / 2;
   101→
   102→      ctx.save();
   103→      ctx.shadowColor = 'rgba(0,0,0,0.5)';
   104→      ctx.shadowBlur = 15;
   105→      ctx.shadowOffsetY = 10;
   106→      ctx.drawImage(image, sx, sy, srcTileW, srcTileH, ddx, ddy, dragW, dragH);
   107→      ctx.strokeStyle = '#ccff00';
   108→      ctx.lineWidth = 2;
   109→      ctx.strokeRect(ddx, ddy, dragW, dragH);
   110→      ctx.restore();
   111→    }
   112→  }
   113→};
