   352→  // ---------------------------------------------------------------
   353→  // Hand analysis helpers
   354→  // ---------------------------------------------------------------
   355→  function pinchDistance(hand) {
   356→    const thumb = hand[4];
   357→    const index = hand[8];
   358→    return Math.hypot(thumb.x - index.x, thumb.y - index.y);
   359→  }
   360→
   361→  function isPinching(hand) {
   362→    return pinchDistance(hand) < PINCH_THRESHOLD;
   363→  }
   364→
   365→  function isFrameGesture(hand) {
   366→    // Thumb and index spread apart
   367→    return Math.hypot(hand[8].x - hand[4].x, hand[8].y - hand[4].y) > FRAME_THRESHOLD;
   368→  }
   369→
   370→  function isFist(hand) {
   371→    const wrist = hand[0];
   372→    const tips = [8, 12, 16, 20];
   373→    const pips = [6, 10, 14, 18];
   374→    let closed = 0;
   375→    for (let i = 0; i < tips.length; i++) {
   376→      const tip = hand[tips[i]];
   377→      const pip = hand[pips[i]];
   378→      const dTip = Math.hypot(tip.x - wrist.x, tip.y - wrist.y);
   379→      const dPip = Math.hypot(pip.x - wrist.x, pip.y - wrist.y);
   380→      if (dTip < dPip) closed++;
   381→    }
   382→    return closed === 4;
   383→  }
   384→
   385→  // ---------------------------------------------------------------
   386→  // Skeleton drawing
   387→  // ---------------------------------------------------------------
   388→  function drawSkeleton(allLandmarks, width, height) {
   389→    for (const landmarks of allLandmarks) {
   390→      // Draw connections
   391→      ctx.strokeStyle = '#ffffff';
   392→      ctx.lineWidth = 3;
   393→      for (const [a, b] of HAND_CONNECTIONS) {
   394→        ctx.beginPath();
   395→        ctx.moveTo((1 - landmarks[a].x) * width, landmarks[a].y * height);
   396→        ctx.lineTo((1 - landmarks[b].x) * width, landmarks[b].y * height);
   397→        ctx.stroke();
   398→      }
   399→      // Draw joints
   400→      for (let i = 0; i < landmarks.length; i++) {
   401→        const lm = landmarks[i];
   402→        ctx.beginPath();
   403→        ctx.arc((1 - lm.x) * width, lm.y * height, 3, 0, Math.PI * 2);
   404→        ctx.fillStyle = '#ffffff';
   405→        ctx.fill();
   406→      }
   407→    }
   408→  }
