   410→  // ---------------------------------------------------------------
   411→  // Main render loop
   412→  // ---------------------------------------------------------------
   413→  function renderLoop() {
   414→    if (!canvas || !cameraReady) {
   415→      requestAnimationFrame(renderLoop);
   416→      return;
   417→    }
   418→
   419→    if (video.readyState < 2) {
   420→      requestAnimationFrame(renderLoop);
   421→      return;
   422→    }
   423→
   424→    // Match canvas to video size
   425→    if (canvas.width !== video.videoWidth || canvas.height !== video.videoHeight) {
   426→      canvas.width = video.videoWidth;
   427→      canvas.height = video.videoHeight;
   428→    }
   429→
   430→    const width = canvas.width;
   431→    const height = canvas.height;
   432→    ctx.clearRect(0, 0, width, height);
   433→
   434→    // Detect hands
   435→    let results = null;
   436→    if (gestureCtrl && modelLoaded) {
   437→      results = gestureCtrl.detectRaw(video);
   438→    }
   439→
   440→    // ---- SCANNING / LEADERBOARD ----
   441→    if (gameState === 'SCANNING' || gameState === 'LEADERBOARD') {
   442→      // Draw mirrored camera
   443→      ctx.save();
   444→      ctx.translate(width, 0);
   445→      ctx.scale(-1, 1);
   446→      ctx.drawImage(video, 0, 0, width, height);
   447→      ctx.restore();
   448→
   449→      if (gameState === 'SCANNING') {
   450→        handleScanning(results, width, height);
   451→      }
   452→    }
   453→
   454→    // ---- PLAYING / SOLVED ----
   455→    else if ((gameState === 'PLAYING' || gameState === 'SOLVED') && puzzleImageCanvas && boardCoords) {
   456→      // Draw mirrored camera background
   457→      ctx.save();
   458→      ctx.translate(width, 0);
   459→      ctx.scale(-1, 1);
   460→      ctx.drawImage(video, 0, 0, width, height);
   461→      ctx.restore();
   462→
   463→      handlePlaying(results, width, height);
   464→    }
   465→
   466→    // Draw skeleton (except during leaderboard)
   467→    if (results && results.landmarks && results.landmarks.length > 0 && gameState !== 'LEADERBOARD') {
   468→      drawSkeleton(results.landmarks, width, height);
   469→    }
   470→
   471→    requestAnimationFrame(renderLoop);
   472→  }
